sql:
SELECT AVG(yield_ton) AS average_yield
FROM yields
WHERE year = 2022 AND crop_id = 1;

SELECT yield_ton
FROM yields
WHERE crop_id = 1 AND year = 2022;

SELECT AVG(yield_ton) AS average_yield
FROM yields
WHERE crop_id = 1 AND county_id = 1;

SELECT crop_name
FROM crops
WHERE crop_id = 1;

